var beforePrint=function beforePrint(){console.log("Functionality to run before printing.");document.body.classList.add("printing");};var afterPrint=function afterPrint(){console.log("Functionality to run after printing");document.body.classList.remove("printing");};window.onbeforeprint=beforePrint;window.onafterprint=afterPrint;